1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	
21	function basePremium(item: any): number {
22	  return BASE_PREMIUMS[item.type] ?? 0;
23	}
24	
25	export function claimOffice(input: any): unknown {
26	  const results = [];
27	  for (const step of input.steps) {
28	    validateItemTypes(step.items);
29	    let premium = PROCESSING_FEE;
30	    for (const item of step.items) {
31	      premium += basePremium(item);
32	    }
33	    results.push({ premium });
34	  }
35	  return { results };
36	}
